import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, renderHook } from "@testing-library/react";
import { type RefObject, useRef } from "react";
import { afterEach, describe, expect, it } from "vitest";
import { useFocusTrap } from "./use-focus-trap.js";

// File convention: this suite asserts focus-trap focus movement to specific
// elements identified by `#id`. The buttons are intentionally labelled "A"/"B"/"C"
// to keep the test fixtures minimal — they share no distinguishing accessible name,
// so `getByRole` cannot identify the focused target. AGENTS.md keys library rules
// require this pattern: "test actual focus movement, active descendant, boundary
// callbacks, editable-target behavior." See TESTING.md rule 2 for the documented
// exception. Every `querySelector("#id")` call below carries the inline marker so
// per-line audits pass.

function createContainerIn(ownerDocument: Document, ...focusableHTML: string[]) {
  const container = ownerDocument.createElement("div");
  container.tabIndex = -1;
  for (const html of focusableHTML) {
    container.insertAdjacentHTML("beforeend", html);
  }
  ownerDocument.body.appendChild(container);
  return container;
}

function createContainer(...focusableHTML: string[]) {
  return createContainerIn(document, ...focusableHTML);
}

function fireTabFromActive(ownerDocument: Document, shiftKey = false) {
  const KeyboardEventCtor = ownerDocument.defaultView?.KeyboardEvent ?? KeyboardEvent;
  const event = new KeyboardEventCtor("keydown", {
    key: "Tab",
    shiftKey,
    bubbles: true,
    cancelable: true,
  });
  ownerDocument.activeElement?.dispatchEvent(event);
  return event;
}

function fireTab(shiftKey = false) {
  return fireTabFromActive(document, shiftKey);
}

describe("useFocusTrap", () => {
  let container: HTMLDivElement;

  afterEach(() => {
    cleanup();
    container?.remove();
  });

  function renderTrap(
    containerEl: HTMLDivElement,
    options?: Parameters<typeof useFocusTrap>[1],
  ) {
    return renderHook(
      ({ opts }) => {
        const ref = useRef<HTMLElement>(containerEl);
        useFocusTrap(ref, opts);
      },
      { initialProps: { opts: options } },
    );
  }

  describe("initial focus", () => {
    it("focuses first focusable element", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("falls back to container when no focusable children", () => {
      container = createContainer("<p>No focusable</p>");
      renderTrap(container);
      expect(document.activeElement).toBe(container);

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);
    });

    it("respects initialFocus ref", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#b")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });

    it("respects programmatic initialFocus targets with negative tabindex", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      expect(document.activeElement).toBe(targetEl);
    });
  });

  describe("Tab cycling", () => {
    it("wraps focus bidirectionally (Tab and Shift+Tab)", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.focus();
      const tabEvent = fireTab();
      expect(tabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      const shiftTabEvent = fireTab(true);
      expect(shiftTabEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("includes focusable nodes added after the trap activated", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);

      container.insertAdjacentHTML("beforeend", '<button id="c">C</button>');

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const newLast = container.querySelector<HTMLElement>("#c")!;
      newLast.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("uses tabbable order for positive tabindex and skips negative tabindex boundaries", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b" tabindex="2">B</button>',
        '<button id="c" tabindex="1">C</button>',
        '<button id="d" tabindex="-1">D</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#a")!;
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("moves from a programmatic initial target to the first tabbable element on Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("moves from a programmatic initial target to the last tabbable element on Shift+Tab", () => {
      container = createContainer(
        '<div id="a" tabindex="-1">A</div>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const targetEl = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(targetEl);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      const event = fireTab(true);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#c"));
    });

    it("cycles focus within the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();
      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#b")!;
      last.focus();
      const event = fireTabFromActive(frameDocument!);
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      frame.remove();
    });
  });

  describe("focus restoration", () => {
    it("restores focus on unmount when restoreFocus is true", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("does not restore focus when restoreFocus is false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      expect(document.activeElement).toBe(outsideButton);

      container = createContainer('<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: false });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(document.activeElement).not.toBe(outsideButton);

      outsideButton.remove();
    });

    it("restores focus when enabled changes from true to false", () => {
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: true } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      rerender({ enabled: false });
      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("captures and restores focus inside the trap container's owning document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const outsideButton = frameDocument?.createElement("button");
      outsideButton.textContent = "Outside";
      frameDocument?.body.append(outsideButton);
      outsideButton.focus();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      container = createContainerIn(frameDocument!, '<button id="a">A</button>');
      const { unmount } = renderTrap(container, { restoreFocus: true });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      unmount();
      expect(frameDocument?.activeElement).toBe(outsideButton);

      frame.remove();
    });
  });

  describe("enabled option", () => {
    it("does nothing when enabled is false", () => {
      const outsideButton = document.createElement("button");
      document.body.appendChild(outsideButton);
      outsideButton.focus();

      container = createContainer('<button id="a">A</button>');
      renderTrap(container, { enabled: false });

      expect(document.activeElement).toBe(outsideButton);

      outsideButton.remove();
    });

    it("activates when enabled changes from false to true", () => {
      container = createContainer('<button id="a">A</button>');

      const { rerender } = renderHook(
        ({ enabled }) => {
          const ref = useRef<HTMLElement>(container);
          useFocusTrap(ref, { enabled });
        },
        { initialProps: { enabled: false } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).not.toBe(container.querySelector("#a"));

      rerender({ enabled: true });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("moves the trap when the container ref changes", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const firstRef: RefObject<HTMLElement | null> = { current: first };
      const secondRef: RefObject<HTMLElement | null> = { current: second };

      const { rerender } = renderHook(
        ({ ref }) => {
          useFocusTrap(ref);
        },
        { initialProps: { ref: firstRef } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      rerender({ ref: secondRef });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("focusable filtering", () => {
    it("chooses the first focusable descendant when non-focusable nodes appear first", () => {
      container = createContainer(
        '<button id="a" style="display:none">Hidden</button>',
        '<button id="disabled" disabled>Disabled</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });

    it("recaptures focus when the focused element becomes disabled", async () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const btnA = container.querySelector<HTMLButtonElement>("#a")!;
      expect(document.activeElement).toBe(btnA);

      await act(async () => {
        btnA.disabled = true;
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("initialFocus guards", () => {
    it("ignores initialFocus when its node is outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(outsideButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("ignores initialFocus when its node is not focusable", () => {
      container = createContainer(
        '<button id="a" disabled>A</button>',
        '<button id="b">B</button>',
      );
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const disabledButton = container.querySelector<HTMLElement>("#a")!;

      renderHook(() => {
        const ref = useRef<HTMLElement>(container);
        const initialRef = useRef<HTMLElement>(disabledButton);
        useFocusTrap(ref, { initialFocus: initialRef });
      });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));
    });
  });

  describe("ref node mutation", () => {
    it("retraps focus on the new container when the trap target swaps in-place", () => {
      const first = createContainer('<button id="a">A</button>');
      const second = createContainer('<button id="b">B</button>');
      container = first;
      const stableRef: RefObject<HTMLElement | null> = { current: first };

      const { rerender } = renderHook(
        ({ tick }) => {
          useFocusTrap(stableRef, { restoreFocus: false });
          return tick;
        },
        { initialProps: { tick: 0 } },
      );

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(first.querySelector("#a"));

      stableRef.current = second;
      rerender({ tick: 1 });

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(second.querySelector("#b"));

      second.remove();
    });
  });

  describe("nested trap stack", () => {
    it("inner trap captures focus while outer trap is suspended, and outer recaptures on inner release", () => {
      // Set up outer trap
      container = createContainer(
        '<button id="o1">O1</button>',
        '<button id="o2">O2</button>',
      );
      const outerEl = container;
      const outerRef: RefObject<HTMLElement | null> = { current: outerEl };
      const innerEl = createContainer(
        '<button id="i1">I1</button>',
        '<button id="i2">I2</button>',
      );
      const innerRef: RefObject<HTMLElement | null> = { current: innerEl };

      // Render both traps in a single component to share the React tree.
      // The inner trap is toggled via a prop.
      const { rerender } = renderHook(
        ({ innerEnabled }: { innerEnabled: boolean }) => {
          useFocusTrap(outerRef, { restoreFocus: false });
          useFocusTrap(innerRef, { restoreFocus: false, enabled: innerEnabled });
        },
        { initialProps: { innerEnabled: false } },
      );

      // Outer trap has focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      // Enable inner trap
      rerender({ innerEnabled: true });

      // Inner trap should capture focus
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Tab inside inner trap should wrap within inner, not escape to outer
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const innerLast = innerEl.querySelector<HTMLElement>("#i2")!;
      innerLast.focus();
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Focus escaping to outside should be recaptured by the inner trap,
      // not the outer (outer is suspended).
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(innerEl.querySelector("#i1"));

      // Disable inner trap — outer should recapture focus
      rerender({ innerEnabled: false });

      // Focus should be back in the outer trap's container
      expect(outerEl.contains(document.activeElement)).toBe(true);

      // Tab should now work within outer trap
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const outerLast = outerEl.querySelector<HTMLElement>("#o2")!;
      outerLast.focus();
      const outerEvent = fireTab();
      expect(outerEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(outerEl.querySelector("#o1"));

      outsideButton.remove();
      innerEl.remove();
    });
  });

  describe("document-level capture and focusin recapture", () => {
    it("recaptures focus on the next Tab when focus has escaped outside the container", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );
      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      renderTrap(container);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // Focus escapes outside the container — the document-level focusin
      // listener should recapture back to the last in-trap element.
      outsideButton.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const second = container.querySelector<HTMLElement>("#b")!;
      second.focus();
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#b"));

      // Tab from in-trap should still wrap correctly after a prior escape.
      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));

      outsideButton.remove();
    });

    it("traps Tab even when a descendant calls stopPropagation on keydown", () => {
      container = createContainer(
        '<button id="a">A</button>',
        '<button id="b">B</button>',
        '<button id="c">C</button>',
      );
      renderTrap(container);

      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const last = container.querySelector<HTMLElement>("#c")!;
      last.addEventListener("keydown", (e) => e.stopPropagation());
      last.focus();

      const event = fireTab();
      expect(event.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(document.activeElement).toBe(container.querySelector("#a"));
    });

    it("listens on the trap container's owning document, not the host document", () => {
      const frame = document.createElement("iframe");
      document.body.append(frame);
      const frameDocument = frame.contentDocument;
      expect(frameDocument).not.toBeNull();

      const hostOutside = document.createElement("button");
      hostOutside.id = "host-outside";
      document.body.appendChild(hostOutside);
      hostOutside.focus();

      container = createContainerIn(
        frameDocument!,
        '<button id="a">A</button>',
        '<button id="b">B</button>',
      );

      renderTrap(container, { restoreFocus: false });
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      // Tab in the host document must NOT be intercepted by the iframe trap.
      hostOutside.focus();
      expect(document.activeElement).toBe(hostOutside);
      const hostEvent = fireTabFromActive(document);
      expect(hostEvent.defaultPrevented).toBe(false);

      // Tab inside the iframe document IS intercepted.
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      const frameLast = container.querySelector<HTMLElement>("#b")!;
      frameLast.focus();
      const frameEvent = fireTabFromActive(frameDocument!);
      expect(frameEvent.defaultPrevented).toBe(true);
      // querySelector by id: testing focus movement to non-accessible-name target (keys library convention per AGENTS.md)
      expect(frameDocument?.activeElement).toBe(container.querySelector("#a"));

      hostOutside.remove();
      frame.remove();
    });

    it("recaptures focus to the container when no tabbable children exist and container had no tabindex", () => {
      container = document.createElement("div");
      container.insertAdjacentHTML("beforeend", "<p>No focusable</p>");
      document.body.appendChild(container);
      expect(container.hasAttribute("tabindex")).toBe(false);

      const outsideButton = document.createElement("button");
      outsideButton.id = "outside";
      document.body.appendChild(outsideButton);

      const { unmount } = renderTrap(container, { restoreFocus: false });

      // Trap activation focuses the container after assigning tabindex=-1.
      expect(document.activeElement).toBe(container);

      // Focus escapes; document-level focusin recaptures to the container.
      outsideButton.focus();
      expect(document.activeElement).toBe(container);

      // Tab from outside the trap is intercepted via document-level capture and
      // refocuses the container (since it is the only focusable target).
      outsideButton.focus();
      const tabEvent = fireTabFromActive(document);
      expect(tabEvent.defaultPrevented).toBe(true);
      expect(document.activeElement).toBe(container);

      unmount();
      // Trap teardown removes the temporary tabindex it assigned.
      expect(container.hasAttribute("tabindex")).toBe(false);

      outsideButton.remove();
    });
  });
});

import { act, cleanup, render, renderHook } from "@testing-library/react";
import { useEffect } from "react";
import { afterEach, describe, expect, it, vi } from "vitest";
import { useKeyboardContext } from "../providers/keyboard-context.js";
import { KeyboardWrapper, fireKey as pressKey, StrictKeyboardWrapper } from "../testing/test-utils.js";
import { useKey } from "./use-key.js";
import { useScope } from "./use-scope.js";

describe("useScope", () => {
  afterEach(() => {
    cleanup();
  });

  it("scope push/pop lifecycle: active scope receives events, previous scope resumes on unmount", () => {
    const globalHandler = vi.fn();
    const modalHandler = vi.fn();

    function GlobalConsumer() {
      const { register } = useKeyboardContext();
      useEffect(() => register("global", "Escape", globalHandler), []);
      return null;
    }

    function ModalConsumer() {
      const { register } = useKeyboardContext();
      useScope("modal");
      useEffect(() => register("modal", "Escape", modalHandler), []);
      return null;
    }

    const { rerender } = render(
      <KeyboardWrapper>
        <GlobalConsumer />
        <ModalConsumer />
      </KeyboardWrapper>,
    );

    // While modal scope is active, only modal handlers fire
    act(() => pressKey("Escape"));
    expect(modalHandler).toHaveBeenCalledOnce();
    expect(globalHandler).not.toHaveBeenCalled();

    // Unmount the modal consumer — useScope cleanup pops "modal"
    rerender(
      <KeyboardWrapper>
        <GlobalConsumer />
      </KeyboardWrapper>,
    );

    // After pop, global scope is active again
    act(() => pressKey("Escape"));
    expect(globalHandler).toHaveBeenCalledOnce();
  });

  it("does not push scope when enabled is false", () => {
    const globalHandler = vi.fn();
    const modalHandler = vi.fn();

    function Consumer() {
      const { register } = useKeyboardContext();
      useScope("modal", { enabled: false });
      useEffect(() => {
        const c1 = register("global", "Escape", globalHandler);
        const c2 = register("modal", "Escape", modalHandler);
        return () => { c1(); c2(); };
      }, []);
      return <div>consumer</div>;
    }

    render(
      <KeyboardWrapper>
        <Consumer />
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // Scope was not pushed, so active scope is still "global"
    expect(globalHandler).toHaveBeenCalledOnce();
    expect(modalHandler).not.toHaveBeenCalled();
  });

  it("keeps the last sibling scope active when many scopes mount together", () => {
    const handlers = Array.from({ length: 40 }, () => vi.fn());

    function ScopedConsumer({ index }: { index: number }) {
      const scope = `scope-${index}`;
      useScope(scope);
      useKey("Escape", handlers[index]!, { scope });
      return null;
    }

    render(
      <KeyboardWrapper>
        {handlers.map((_, index) => (
          <ScopedConsumer key={index} index={index} />
        ))}
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));

    expect(handlers.at(-1)).toHaveBeenCalledOnce();
    for (const handler of handlers.slice(0, -1)) {
      expect(handler).not.toHaveBeenCalled();
    }
  });

  it("keeps a nested child scope active over its parent scope", () => {
    const parentHandler = vi.fn();
    const childHandler = vi.fn();

    function ChildScope() {
      const scope = useScope("child");
      useKey("Escape", childHandler, { scope });
      return null;
    }

    function ParentScope() {
      const scope = useScope("parent");
      useKey("Escape", parentHandler, { scope });
      return <ChildScope />;
    }

    render(
      <KeyboardWrapper>
        <ParentScope />
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));

    expect(childHandler).toHaveBeenCalledOnce();
    expect(parentHandler).not.toHaveBeenCalled();
  });

  it("throws when used outside KeyboardProvider", () => {
    expect(() => {
      renderHook(() => useScope("modal"));
    }).toThrow("useKeyboardContext must be used within KeyboardProvider");
  });

  it("returns the resolved scope name when enabled and null when disabled", () => {
    const seen: Array<string | null> = [];

    function Consumer({ enabled }: { enabled: boolean }) {
      const scope = useScope("modal", { enabled });
      seen.push(scope);
      return null;
    }

    const { rerender } = render(
      <KeyboardWrapper>
        <Consumer enabled={false} />
      </KeyboardWrapper>,
    );
    expect(seen[seen.length - 1]).toBeNull();

    rerender(
      <KeyboardWrapper>
        <Consumer enabled={true} />
      </KeyboardWrapper>,
    );
    expect(seen[seen.length - 1]).toBe("modal");
  });

  it("colocated implicit useKey fires when a disabled scope becomes enabled", () => {
    const handler = vi.fn();

    function Modal({ enabled }: { enabled: boolean }) {
      const scope = useScope("modal", { enabled });
      useKey("Escape", handler, { scope });
      return null;
    }

    const { rerender } = render(
      <KeyboardWrapper>
        <Modal enabled={false} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    expect(handler).not.toHaveBeenCalled();

    rerender(
      <KeyboardWrapper>
        <Modal enabled={true} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    expect(handler).toHaveBeenCalledOnce();
  });

  it("colocated useKey stops firing when an enabled scope becomes disabled, leaving no stale handlers", () => {
    const handler = vi.fn();

    function Modal({ enabled }: { enabled: boolean }) {
      const scope = useScope("modal", { enabled });
      useKey("Escape", handler, { scope });
      return null;
    }

    const { rerender } = render(
      <KeyboardWrapper>
        <Modal enabled={true} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // call-count IS the contract: handler fires once while scope is enabled
    expect(handler).toHaveBeenCalledTimes(1);

    rerender(
      <KeyboardWrapper>
        <Modal enabled={false} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // call-count IS the contract: handler must NOT fire after scope becomes disabled (count stays at 1, no stale registration)
    expect(handler).toHaveBeenCalledTimes(1);
  });

  it("parent global useKey mounted in same commit as sibling scope remains in global scope", () => {
    const parentHandler = vi.fn();
    const childHandler = vi.fn();

    function ParentKey() {
      useKey("o", parentHandler);
      return null;
    }

    function ChildScope() {
      const scope = useScope("modal");
      useKey("Escape", childHandler, { scope });
      return null;
    }

    function App() {
      return (
        <>
          <ParentKey />
          <ChildScope />
        </>
      );
    }

    render(
      <KeyboardWrapper>
        <App />
      </KeyboardWrapper>,
    );

    act(() => pressKey("o"));
    expect(parentHandler).not.toHaveBeenCalled();

    act(() => pressKey("Escape"));
    expect(childHandler).toHaveBeenCalledOnce();
  });

  it("parent useKey explicitly scoped to 'global' is unaffected by descendant scope pushes", () => {
    const parentHandler = vi.fn();
    const childHandler = vi.fn();

    function ChildWithScope() {
      const scope = useScope("modal");
      useKey("Escape", childHandler, { scope });
      return null;
    }

    function ParentWithKey() {
      useKey("o", parentHandler, { scope: "global" });
      return <ChildWithScope />;
    }

    render(
      <KeyboardWrapper>
        <ParentWithKey />
      </KeyboardWrapper>,
    );

    act(() => pressKey("o"));
    expect(parentHandler).not.toHaveBeenCalled();

    act(() => pressKey("Escape"));
    expect(childHandler).toHaveBeenCalledOnce();
  });

  it("parent global useKey resumes firing once a child scope unmounts and pops", () => {
    const parentHandler = vi.fn();
    const childHandler = vi.fn();

    function ParentKey() {
      useKey("o", parentHandler);
      return null;
    }

    function ChildScope() {
      useScope("modal");
      useKey("Escape", childHandler);
      return null;
    }

    function App({ open }: { open: boolean }) {
      return (
        <>
          <ParentKey />
          {open ? <ChildScope /> : null}
        </>
      );
    }

    const { rerender } = render(
      <KeyboardWrapper>
        <App open={false} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("o"));
    expect(parentHandler).toHaveBeenCalledOnce();

    rerender(
      <KeyboardWrapper>
        <App open={true} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("o"));
    expect(parentHandler).toHaveBeenCalledOnce();

    act(() => pressKey("Escape"));
    expect(childHandler).toHaveBeenCalledOnce();

    rerender(
      <KeyboardWrapper>
        <App open={false} />
      </KeyboardWrapper>,
    );

    act(() => pressKey("o"));
    // call-count IS the contract: parent handler must resume firing after the child scope unmounts (count increments to 2, proving scope pop restored the registration)
    expect(parentHandler).toHaveBeenCalledTimes(2);
  });

  it("survives StrictMode mount → unmount → mount cycles without leaking handlers", () => {
    const handler = vi.fn();

    function Consumer() {
      const scope = useScope("modal");
      useKey("Escape", handler, { scope });
      return null;
    }

    const { unmount } = render(
      <StrictKeyboardWrapper>
        <Consumer />
      </StrictKeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // call-count IS the contract: StrictMode mount/unmount/mount must NOT cause duplicate registrations (count is 1, not 2)
    expect(handler).toHaveBeenCalledTimes(1);

    unmount();

    act(() => pressKey("Escape"));
    // call-count IS the contract: unmount cleanup must remove the registration (count stays at 1, no leaked handler)
    expect(handler).toHaveBeenCalledTimes(1);
  });

  it("disabling and re-enabling within StrictMode does not leave duplicate registrations", () => {
    const handler = vi.fn();

    function Consumer({ enabled }: { enabled: boolean }) {
      const scope = useScope("modal", { enabled });
      useKey("Escape", handler, { scope });
      return null;
    }

    const { rerender } = render(
      <StrictKeyboardWrapper>
        <Consumer enabled={true} />
      </StrictKeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // call-count IS the contract: enabled scope fires handler once (no StrictMode-induced duplicate)
    expect(handler).toHaveBeenCalledTimes(1);

    rerender(
      <StrictKeyboardWrapper>
        <Consumer enabled={false} />
      </StrictKeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // call-count IS the contract: disabled scope must NOT fire handler (count stays at 1)
    expect(handler).toHaveBeenCalledTimes(1);

    rerender(
      <StrictKeyboardWrapper>
        <Consumer enabled={true} />
      </StrictKeyboardWrapper>,
    );

    act(() => pressKey("Escape"));
    // call-count IS the contract: re-enabling registers exactly one handler (count is 2, not 3 or more — no StrictMode duplicates after disable/enable cycle)
    expect(handler).toHaveBeenCalledTimes(2);
  });
});
